#include<bits/stdc++.h>
using namespace std;
int n,m;
int fz(int a){
	int n=0,k=a;
	while(k){
		n=n*10+k%10;
		k/=10;
	}
	return n;
}
bool zs(int a){
	for(int i=2;i*i<=a;i++){
		if(a%i==0){
			return false;
		}
	}
	return true;
}
int main() {
	cin>>n>>m;
	for(int i=n;i<=m;i++){
		if(zs(i)&&zs(fz(i))){
			cout<<i<<"\n";
		}
	}
	return 0;
}
